sub is_valid_redirect {
    my ($url) = @_;

    return 0 unless defined $url && $url ne '';

    # Allow relative URLs starting with /
    if ($url =~ m{^/[^/\\]}) {
        # Block protocol-relative URLs and backslash tricks
        return 0 if $url =~ m{^//};
        return 0 if $url =~ m{\\};
        # Block any embedded newlines or carriage returns (header injection)
        return 0 if $url =~ /[\r\n]/;
        # Block data: or javascript: schemes hidden in path
        return 0 if $url =~ /(?:javascript|data|vbscript)\s*:/i;
        return 1;
    }

    # For absolute URLs, parse and validate the host
    my $uri = eval { URI->new($url) };
    return 0 unless $uri;

    my $scheme = $uri->scheme // '';
    return 0 unless $scheme eq 'http' || $scheme eq 'https';

    my $host = $uri->host // '';
    return 0 unless $host ne '';

    # Check against allowed hosts whitelist
    my $is_allowed = 0;
    foreach my $allowed_host (@allowed_hosts) {
        if (lc($host) eq lc($allowed_host)) {
            $is_allowed = 1;
            last;
        }
    }

    return 0 unless $is_allowed;

    # Block newlines/carriage returns in URL (header injection prevention)
    return 0 if $url =~ /[\r\n]/;

    return 1;
}

sub sanitize_url {
    my ($url) = @_;

